// // This module is designed to decrement the count value on each rising edge of the clock input when the enable signal is asserted. The counter resets to zero when the reset input is activated.
module top_module(input clk, input reset, input enable,
   output reg [3:0] count);always @(posedge clk)
     if (reset)
       count <= 0;
     else if (enable)
       count <= count + 1;

endmodule
